{
  "competency_groups": [
    {
      "code": "C-2.1",
      "title": "Historical Events and Processes Analysis",
      "description": "Explain historical events and processes with different types of sources with specific examples from India and world history.",
      "competencies": [
        "Explain historical events and processes using various source types (primary/secondary) with specific examples."
      ],
      "unit_name": "History - India and the Contemporary World - I",
      "chapter_name": ""
    },
    {
      "code": "C-2.3",
      "title": "Continuity and Change in History",
      "description": "Trace aspects of continuity and change in different phases of world history (including cultural trends, social and religious reforms, and economic and political transformations).",
      "competencies": [
        "Identify patterns of continuity and change across historical periods."
      ],
      "unit_name": "History - India and the Contemporary World - I",
      "chapter_name": ""
    },
    {
      "code": "C-2.4",
      "title": "Emergence of New Ideas and Practices",
      "description": "Explain the growth of new ideas and practices across the world and how they affected the course of world history.",
      "competencies": [
        "Analyze the impact of emerging ideologies on historical trajectories."
      ],
      "unit_name": "History - India and the Contemporary World - I",
      "chapter_name": ""
    },
    {
      "code": "C-2.5",
      "title": "Critical Evaluation of Historical Practices",
      "description": "Recognise various practices that arose, such as those in C- 2.4, and came to be condemned later on (such as racism, slavery, colonial invasions, conquests, plunder, genocides), all of which have also impacted the course of world history.",
      "competencies": [
        "Critically evaluate historical practices that led to human rights violations."
      ],
      "unit_name": "History - India and the Contemporary World - I",
      "chapter_name": ""
    },
    {
      "code": "C3.2",
      "title": "Indian National Freedom Struggle Analysis",
      "description": "Identify and analyse important phases of the Indian national freedom struggle against British colonial rule, with special reference to the movement led by Mahatma Gandhi.",
      "competencies": [
        "Analyze key movements in India's independence struggle."
      ],
      "unit_name": "History - India and the Contemporary World - II",
      "chapter_name": ""
    },
    {
      "code": "C-4.1",
      "title": "Geographical Location and Physiography Identification",
      "description": "Locate physiographic regions of India and the climatic zones of the world on a globe/map.",
      "competencies": [
        "Map identification skills for physical features."
      ],
      "unit_name": "Geography - Contemporary India - I",
      "chapter_name": ""
    },
    {
      "code": "C-4.2",
      "title": "Physical Geography Concepts and Characteristics",
      "description": "Explain important geographical concepts, characteristics of key landforms, their origin, and other physical factors of a region.",
      "competencies": [
        "Understand the formation and characteristics of major landforms."
      ],
      "unit_name": "Geography - Contemporary India - I",
      "chapter_name": ""
    },
    {
      "code": "C-4.3",
      "title": "Inter-linkages in Physical Environment",
      "description": "Draw inter- linkages between various components of the physical environment, such as climate and relief, climate and vegetation, vegetation, and wildlife.",
      "competencies": [
        "Analyze relationships between climatic conditions, landforms, flora, and fauna."
      ],
      "unit_name": "Geography - Contemporary India - I",
      "chapter_name": ""
    },
    {
      "code": "C-4.4",
      "title": "Human-Nature Interrelationship Analysis",
      "description": "Analyse and evaluate the inter- relationship between the natural environment and human beings and their cultures across regions.",
      "competencies": [
        "Evaluate how culture is shaped by environmental factors."
      ],
      "unit_name": "Geography - Contemporary India - I",
      "chapter_name": ""
    },
    {
      "code": "C-4.5",
      "title": "Environmental Impact Evaluation and Conservation Strategies",
      "description": "Critically evaluate the impact of human interventions on the environment, including climate change, pollution, shortages of natural resources (particularly water), and loss of biodiversity.",
      "competencies": [
        "Identify causes of environmental crises."
      ],
      "unit_name": "Geography - Contemporary India - I",
      "chapter_name": ""
    },
    {
      "code": "C-4.6",
      "title": "Resource Conservation Sensitivity and Planning",
      "description": "Develop sensitivity towards the judicious use of natural resources (by individuals, societies, and nations) and suggests measures for their conservation.",
      "competencies": [
        "Propose strategies for sustainable resource management."
      ],
      "unit_name": "Geography - Contemporary India - I",
      "chapter_name": ""
    },
    {
      "code": "C-5.1",
      "title": "Constitutional Heritage and Democratic Origins",
      "description": "Understand that the Indian Constitution draws from the great cultural heritage and common aspirations of the Indian nation, recalling India's early experiments with democracy.",
      "competencies": [
        "Connect historical democratic practices to modern constitutional values."
      ],
      "unit_name": "Political Science - Democratic Politics - I",
      "chapter_name": ""
    },
    {
      "code": "C-5.2",
      "title": "Constitutional Values Appreciation",
      "description": "Appreciate fundamental Constitutional values and identify their significance for the prosperity of the Indian nation.",
      "competencies": [
        "Articulate the importance of constitutional principles."
      ],
      "unit_name": "Political Science - Democratic Politics - I",
      "chapter_name": ""
    },
    {
      "code": "C-5.3",
      "title": "Fundamental Rights and Duties Understanding",
      "description": "Explain that fundamental rights are the most basic human rights, and they flourish when people also perform their fundamental duties.",
      "competencies": [
        "Understand the symbiotic relationship between rights and duties."
      ],
      "unit_name": "Political Science - Democratic Politics - I",
      "chapter_name": ""
    },
    {
      "code": "C-5.4",
      "title": "Democratic Government Analysis",
      "description": "Analyse the basic features of a democracy and democratic government – and its history in India and across the world.",
      "competencies": [
        "Compare different forms of governance."
      ],
      "unit_name": "Political Science - Democratic Politics - I",
      "chapter_name": ""
    },
    {
      "code": "C-5.5",
      "title": "Role of Non-State Participants in Democracy",
      "description": "Analyse the critical role of non-state and non-market participants (media, civil society) in the functioning of a democratic government.",
      "competencies": [
        "Evaluate the contribution of civil society to democracy."
      ],
      "unit_name": "Political Science - Democratic Politics - I",
      "chapter_name": ""
    },
    {
      "code": "C-6.1",
      "title": "Unity in Diversity and Cultural Integration",
      "description": "Understands how the Indian ethos respected diversity, promoting peaceful coexistence as a great strength.",
      "competencies": [
        "Analyze historical mechanisms of cultural integration."
      ],
      "unit_name": "Political Science - Democratic Politics - I",
      "chapter_name": ""
    },
    {
      "code": "C-6.2",
      "title": "Inequality, Justice and Social Movements Analysis",
      "description": "Understand that despite unity in diversity, forms of inequality have occurred, leading to political, social, and cultural efforts towards equity.",
      "competencies": [
        "Trace historical struggles for justice and inclusion."
      ],
      "unit_name": "Political Science - Democratic Politics - I",
      "chapter_name": ""
    },
    {
      "code": "C-7.1",
      "title": "Economic Features Definition",
      "description": "Defines key features of the economy, such as production, distribution, demand, supply, trade, and commerce.",
      "competencies": [
        "Identify core economic concepts."
      ],
      "unit_name": "Economics (Class IX)",
      "chapter_name": ""
    },
    {
      "code": "C-7.2",
      "title": "Sectoral Importance Evaluation",
      "description": "Evaluates the importance of the three sectors of production in any country's economy.",
      "competencies": [
        "Assess the role of primary, secondary, and tertiary sectors."
      ],
      "unit_name": "Economics (Class IX)",
      "chapter_name": ""
    },
    {
      "code": "C-7.3",
      "title": "Organised vs Unorganised Sector Analysis",
      "description": "Distinguishes between 'unorganised' and 'organised' sectors of the economy and their role in production.",
      "competencies": [
        "Differentiate economic structures."
      ],
      "unit_name": "Economics (Class IX)",
      "chapter_name": ""
    },
    {
      "code": "C-7.4",
      "title": "Trade and Commerce Traceability",
      "description": "Trace the beginning and importance of large-scale trade between countries.",
      "competencies": [
        "Analyze historical shifts in global trade patterns."
      ],
      "unit_name": "Economics (Class IX)",
      "chapter_name": ""
    },
    {
      "code": "C-8.1",
      "title": "Data Analysis on Socio-Economic Indicators",
      "description": "Gather, comprehend, and analyse data related to income, capital, poverty, and employment.",
      "competencies": [
        "Interpret socio-economic statistics."
      ],
      "unit_name": "Economics (Class IX)",
      "chapter_name": ""
    },
    {
      "code": "C-8.3",
      "title": "Ancient Indian Economy Appreciation",
      "description": "Understand features of the ancient economy, including trade networks and industries.",
      "competencies": [
        "Recognize historical economic strengths."
      ],
      "unit_name": "Economics (Class IX)",
      "chapter_name": ""
    },
    {
      "code": "C-8.4",
      "title": "Modern Economic Progress Analysis",
      "description": "Describes India's recent path towards becoming one of the largest economies.",
      "competencies": [
        "Analyze drivers of modern economic growth."
      ],
      "unit_name": "Economics (Class IX)",
      "chapter_name": ""
    },
    {
      "code": "C-8.5",
      "title": "Development and Environment Interconnection",
      "description": "Appreciates the connections between economic development, environment, and societal wellbeing beyond GDP.",
      "competencies": [
        "Evaluate sustainable development indicators."
      ],
      "unit_name": "Economics (Class IX)",
      "chapter_name": ""
    }
  ]
}
